with Session(engine) as s:
    for (oid, name, phone, brand, model, cat, complaint, acc, serial, age, src, acceptor, mid) in orders:
        s.execute(text(f"UPDATE orders SET client_name='{name}', client_phone='{phone}', device_brand='{brand}', device_model='{model}', device_category='{cat}', complaint='{complaint[:1000]}', accessories='{acc}', serial_number='{serial}', age_group='{age}', source='{src}', acceptor_id={acceptor} WHERE id={oid}"))
        s.execute(text(f"DELETE FROM order_services WHERE order_id={oid}"))
        tc = s.execute(text(f"SELECT total_cost FROM orders WHERE id={oid}")).fetchone()[0]
        work = tc or 0
        parts = s.execute(text(f"SELECT COALESCE(parts_cost,0) FROM orders WHERE id={oid}")).fetchone()[0]
        if work > 0 or parts == 0:
            svc_cost = work if work > 0 else (tc or 0)
            s.execute(text(f"INSERT INTO order_services (order_id, service_name, price_at_order, quantity) VALUES ({oid},'Ремонт',{svc_cost},1)"))
        print(f"  #{oid}: {name}")
    s.commit()
    print(f"\n{len(orders)} orders updated")
